import React, { useEffect, useState } from "react";
import axios from "axios";

import { MapContainer, TileLayer, Marker,Popup} from "react-leaflet";
import "leaflet/dist/leaflet.css";

function App() {
  const [email, setEmail] = useState("");
  const [alerts, setAlerts] = useState([]);
  const [showHistory, setShowHistory] = useState(false);

  // SOS function
  const sendSOS = () => {
    if (!email) {
      window.alert("Enter email first!");
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (pos) => {
      const latitude = pos.coords.latitude;
      const longitude = pos.coords.longitude;

      try {
        await axios.post("http://localhost:5000/alert", {
          email,
          latitude,
          longitude
        });

       window.alert("SOS Sent 🚨");
        fetchAlerts();
      } catch (err) {
        console.log(err);
      }
    });
  };

  // Fetch alerts
  const fetchAlerts = async () => {
    const res = await axios.get("http://localhost:5000/alerts");
    setAlerts(res.data);
  };

  useEffect(() => {
    fetchAlerts();
  }, []);

  return (
    <div style={{ textAlign: "center", padding: "20px" }}>
      <input 
        placeholder="Enter Email" 
        onChange={(e) =>
          setEmail(e.target.value)}
          />
    
      <h1>Women Safety App 🚀</h1>

      <button
        onClick={sendSOS}
        style={{
          padding: "15px",
          fontSize: "18px",
          backgroundColor: "red",
          color: "white",
          border: "none",
          borderRadius: "10px"
        }}
      >
        🚨 SOS
      </button>
      <br /><br/>
      <button onClick={() => setShowHistory(!showHistory)}>
        {showHistory ? "Hide History" : "Show History"}
      </button>

      {showHistory && (
        <>
      <h2>Alert History</h2>
      <h2>Live Map</h2>

      <MapContainer
        center={alerts.length ? [alerts[0].latitude, alerts[0].longitude] : [20, 77]}
        zoom={5}
        style={{ height: "300px", width: "80%",margin: "auto" }}
        >
          <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          />

          {alerts.map((a, index) => (
            <Marker key={index}
            position={[a.latitude, a.longitude]}>
              <Popup>
                {a.latitude}, {a.longitude}
              </Popup>
            </Marker>
          ))}
        </MapContainer>

      {alerts.map((a, index) => (
        <div key={index} style={{ margin: "10px" }}>
          📍 {a.latitude}, {a.longitude}
        </div>
      ))}
      </>
      )}
    </div>
  );
}

export default App;
